import{_ as e,o as l,c as a,a2 as o}from"./chunks/framework.Pywvta2k.js";const c=JSON.parse('{"title":"倪海厦","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/05-近现代/03-倪海厦.md","filePath":"tcm-data/05-近现代/03-倪海厦.md","lastUpdated":1781084559000}'),r={name:"tcm-data/05-近现代/03-倪海厦.md"};function n(s,t,i,d,h,g){return l(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="倪海厦" tabindex="-1">倪海厦 <a class="header-anchor" href="#倪海厦" aria-label="Permalink to &quot;倪海厦&quot;">​</a></h1><blockquote><p>倪海厦（1954-2012年），台湾人 海外中医教育的传奇人物 代表作：《人纪》《天纪》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：字海厦</li><li><strong>生平</strong>：自学中医，精通针灸、经方、紫微斗数、风水</li><li><strong>经历</strong>：在美国佛罗里达州开设中医诊所，后通过DVD教学影响全球华人</li><li><strong>著作/教学</strong>：《人纪》（针灸、伤寒、金匮、本草、黄帝内经）、《天纪》（易经、紫微斗数）</li><li><strong>学术地位</strong>：当代中医海外传播第一人</li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-经方为体" tabindex="-1">1. 经方为体 <a class="header-anchor" href="#_1-经方为体" aria-label="Permalink to &quot;1. 经方为体&quot;">​</a></h3><p>倪海厦是坚定的<strong>经方派</strong>，认为：</p><blockquote><p><strong>「经方是中医的正统，时方是经方的变体。」</strong></p></blockquote><h3 id="_2-阴阳辨证" tabindex="-1">2. 阴阳辨证 <a class="header-anchor" href="#_2-阴阳辨证" aria-label="Permalink to &quot;2. 阴阳辨证&quot;">​</a></h3><p>倪海厦特别强调<strong>阴阳</strong>在辨证中的核心地位：</p><ul><li>阴实（肿瘤）→ 阳不能入阴</li><li>阳虚 → 功能衰退</li><li>阴虚 → 物质亏损</li></ul><h3 id="_3-腹诊" tabindex="-1">3. 腹诊 <a class="header-anchor" href="#_3-腹诊" aria-label="Permalink to &quot;3. 腹诊&quot;">​</a></h3><p>倪海厦在《伤寒论》教学中特别强调<strong>腹诊</strong>（腹部触诊）：</p><ul><li>心下痞 → 泻心汤证</li><li>腹满 → 承气汤或理中汤</li><li>少腹急结 → 桃核承气汤</li></ul><h3 id="_4-针灸与中药并用" tabindex="-1">4. 针灸与中药并用 <a class="header-anchor" href="#_4-针灸与中药并用" aria-label="Permalink to &quot;4. 针灸与中药并用&quot;">​</a></h3><blockquote><p><strong>「针灸可以治急症，中药可以治慢病。针药并用，万病一理。」</strong></p></blockquote><hr><h2 id="三、代表方剂-倪海厦常用" tabindex="-1">三、代表方剂（倪海厦常用） <a class="header-anchor" href="#三、代表方剂-倪海厦常用" aria-label="Permalink to &quot;三、代表方剂（倪海厦常用）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">倪海厦特色运用</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>桂枝汤</strong></td><td style="text-align:left;">感冒第一方，兼治自汗、过敏性鼻炎</td></tr><tr><td style="text-align:left;"><strong>小柴胡汤</strong></td><td style="text-align:left;">一切&quot;往来&quot;证（寒热往来、月经先后不定期）</td></tr><tr><td style="text-align:left;"><strong>四逆汤</strong></td><td style="text-align:left;">心衰急救</td></tr><tr><td style="text-align:left;"><strong>真武汤</strong></td><td style="text-align:left;">水肿、头晕、心衰</td></tr><tr><td style="text-align:left;"><strong>乌梅丸</strong></td><td style="text-align:left;">糖尿病（厥阴证）</td></tr><tr><td style="text-align:left;"><strong>麻黄汤</strong></td><td style="text-align:left;">流感、无汗发热</td></tr><tr><td style="text-align:left;"><strong>白虎汤</strong></td><td style="text-align:left;">高热、糖尿病（上消）</td></tr></tbody></table><hr><h2 id="四、经典名言" tabindex="-1">四、经典名言 <a class="header-anchor" href="#四、经典名言" aria-label="Permalink to &quot;四、经典名言&quot;">​</a></h2><blockquote><p><strong>「中医不是慢郎中，是急惊风遇到慢郎中。」</strong></p></blockquote><blockquote><p><strong>「经方才是中医的根本，时方是它的影子。」</strong></p></blockquote><blockquote><p><strong>「学中医，先读《内经》懂生理，再读《伤寒》懂病理。」</strong></p></blockquote><blockquote><p><strong>「腹诊是伤寒论的核心诊法。」</strong></p></blockquote><blockquote><p><strong>「治病的最高境界是不用药——针灸、导引、养生。」</strong></p></blockquote><blockquote><p><strong>「上工治未病，中医的最高境界是预防。」</strong></p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><ul><li>通过DVD教学影响了全球数十万华人中医学习者</li><li>推广经方在海外合法化（美国、欧洲）</li><li>&quot;倪海厦式&quot;的生动教学风格改变了中医教育模式</li></ul><hr><p><em>本条目为精简框架版。可扩展至倪海厦《人纪》教学体系详解、腹诊专题、经方与现代病等。</em></p>',34)])])}const b=e(r,[["render",n]]);export{c as __pageData,b as default};
